form:Form.form:Scripts:
		var GROUP_TREE;
var nSQL;
var Estados;

function onClick()
{                   
	var MyITEM;
	var MyGROUP;
	var MyOBJ;


	MyITEM =GROUP_TREE.GetItem(Ctrl("TREE_ID").GetXValue());
	MyGROUP=GROUP_TREE.GetGroup(Ctrl("TREE_ID").GetXValue());

	MyOBJ=(MyITEM?MyITEM:MyGROUP);
	if (MyOBJ)
	{   
		var subtag=MyOBJ.Tag.split("&")[0];

		switch (subtag)
		{
			case "proyecto-root":
			case "proyecto-child":
		 		Ctrl("OI_PROYECTO").SetXValue(MyOBJ.Id);
				CtrlEnabled("ACCEPT", true);
		 	break;

			default:
				CtrlEnabled("ACCEPT", false);
			break;
		}             
	} else
		CtrlEnabled("ACCEPT", false);
}

function LoadChilds(objTree, objGroup)
{                        
	var subtag=objGroup.Tag.split("&")[0];
	switch (subtag)
	{
		case "root":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:project-root"), ""));
		break;           

		case "find":
			objTree.SetXML(objGroup.FullId, "<tree/>");
		break;

		case "proyecto-root":
		case "proyecto-child":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:project-child"), '<DATA ID="'+objGroup.Id+'" ESTADOS="'+Estados+'" />'));
		break;

 		default:
		break;
	}

}

function FilterGrid()
{ 
	var objGroup;
	if (Ctrl("buscar").GetXValue()!="")  
	{                       
		CtrlEnabled("ACCEPT", false);

		objGroup=GROUP_TREE.GetGroup(".");
		if (objGroup.isExpanded) GROUP_TREE.ContractGroup(objGroup);

		GROUP_TREE.SetXML("*", nSQL.Get(Ctrl("main").getResource("qry:project-find"), '<DATA txt="'+Ctrl("buscar").GetXValue()+'" ESTADOS="'+Estados+'" />'));

		objGroup=GROUP_TREE.GetGroup("*");
		if (!objGroup.isExpanded) GROUP_TREE.ExpandGroup(objGroup,true);
	}
}

function Accept()
{              
}

function OnLoad()
{
	fullId="";
	nSQL=GetProxy().SQLService();

	Estados=Ctrl("ESTADOS").GetXValue();
	if (Estados=="") Estados="T";

 	oi_proyecto=Ctrl("OI_PROYECTO").GetXValue();
 	if (oi_proyecto!="")
 	{

 		fullId=new NomadXML(nSQL.Get(Ctrl("main").getResource("qry:path"), '<DATA oi_proyecto="'+oi_proyecto+'" />'));
 		fullId=fullId.GetAttr("fullId");
 	}                  

	GROUP_TREE=clsClientTree("CONT_PROJECT_TREE","TREE_ID","CLOCK.ico","folder-close.ico","folder.ico","item.ico",true,LoadChilds,null,onClick);

	//Cargo los proyectos
	//GROUP_TREE.SetXML(null, '<tree><group id="." label="Proyectos" imgOpen="cabinet.ico" imgClose="cabinet-close.ico" tag="root" /><group id="*" label="Resultado" imgOpen="cabinet.ico" imgClose="cabinet-close.ico" tag="find" /></tree>');
	GROUP_TREE.SetXML(null, '<tree><group id="." label="Proyectos" imgOpen="cabinet.ico" imgClose="cabinet-close.ico" tag="root" /><group id="*" label="Plantillas" imgOpen="cabinet.ico" imgClose="cabinet-close.ico" tag="template" /></tree>');

	if (fullId=="")
	{       

		CtrlEnabled("ACCEPT", false);
		GROUP_TREE.ClickExpGroup(".");
	} else
	{        
		GROUP_TREE.SetSelectedId(fullId);
	} 


